/*
 * bms_monitor.ino — Smart Battery Management System Monitor
 *
 * Elements:
 *   1. Resistive Cell Voltage Sensing — A0/A1/A2, 3.3 V AREF
 *   2. INA219 I²C Current Monitor     — pack current at 10 Hz
 *   3. SSD1306 OLED                   — live display at 1 Hz
 *   4. Arduino Nano                   — Coulomb counting + alerts
 *
 * Calibration: charge pack to 100 % (4.2 V/cell), reset Q_remaining
 * in EEPROM, then run normally. Re-calibrate after 20 cycles.
 */

#include <Wire.h>
#include <Adafruit_INA219.h>
#include <Adafruit_SSD1306.h>
#include <EEPROM.h>

// --- Config ---
#define CELL_COUNT       3
#define Q_NOM_MAH     2000.0f   // rated capacity in mAh
#define V_MAX_CELL       4.20f
#define V_MIN_CELL       3.00f
#define SOC_WARN_PCT    10.0f
#define BUZZ_PIN           7
#define DIVIDER_RATIO    (147.0f / 100.0f)   // (R1+R2)/R2 = 147/100
#define AREF_MV       3300.0f
#define ADC_BITS        1024.0f
#define POLL_MS          100UL   // INA219 + ADC poll period
#define DISPLAY_MS      1000UL

// EEPROM address for SoC persistence
#define EE_SOC_ADDR       0

// --- Objects ---
Adafruit_INA219  ina;
Adafruit_SSD1306 oled(128, 64, &Wire, -1);

// --- State ---
const uint8_t CELL_PINS[CELL_COUNT] = {A0, A1, A2};
float cell_v[CELL_COUNT];
float current_ma = 0.0f;
float q_remain   = Q_NOM_MAH;   // loaded from EEPROM on boot
float soc_pct    = 100.0f;
bool  alarm      = false;

float read_cell(uint8_t ch) {
  long sum = 0;
  for (int i = 0; i < 8; i++) { sum += analogRead(CELL_PINS[ch]); delay(1); }
  float adc_v = (sum / 8.0f) * AREF_MV / ADC_BITS / 1000.0f;
  return adc_v * DIVIDER_RATIO;
}

void draw_oled() {
  oled.clearDisplay();
  oled.setTextSize(1);
  oled.setTextColor(SSD1306_WHITE);
  oled.setCursor(0,  0); oled.printf("SoC: %.0f %%  %.2fV", soc_pct,
                                      cell_v[0]+cell_v[1]+cell_v[2]);
  for (int i = 0; i < CELL_COUNT; i++) {
    oled.setCursor(0, 12 + i*10);
    oled.printf("C%d: %.3f V", i+1, cell_v[i]);
  }
  oled.setCursor(0, 46);
  oled.printf("I: %.0f mA %s", current_ma, alarm ? "ALARM" : "OK   ");
  oled.display();
}

void setup() {
  Serial.begin(115200);
  analogReference(EXTERNAL);  // use 3.3 V AREF
  Wire.begin();

  ina.begin();
  oled.begin(SSD1306_SWITCHCAPVCC, 0x3C);
  oled.clearDisplay(); oled.display();

  pinMode(BUZZ_PIN, OUTPUT); digitalWrite(BUZZ_PIN, LOW);

  // Load SoC from EEPROM
  EEPROM.get(EE_SOC_ADDR, q_remain);
  if (isnan(q_remain) || q_remain < 0 || q_remain > Q_NOM_MAH) q_remain = Q_NOM_MAH;
  soc_pct = q_remain / Q_NOM_MAH * 100.0f;

  Serial.println(F("BMS monitor ready."));
}

void loop() {
  static unsigned long last_poll    = 0;
  static unsigned long last_display = 0;

  unsigned long now = millis();

  // --- 1. Coulomb counting + cell read ---
  if (now - last_poll >= POLL_MS) {
    float dt_h = POLL_MS / 3600000.0f;   // 100 ms in hours
    last_poll  = now;

    // INA219 current
    current_ma = ina.getCurrent_mA();
    q_remain  -= current_ma * dt_h;  // discharge positive
    q_remain   = constrain(q_remain, 0.0f, Q_NOM_MAH);
    soc_pct    = q_remain / Q_NOM_MAH * 100.0f;

    // Cell voltages
    alarm = false;
    for (int i = 0; i < CELL_COUNT; i++) {
      cell_v[i] = read_cell(i);
      if (cell_v[i] > V_MAX_CELL || cell_v[i] < V_MIN_CELL) alarm = true;
    }
    if (soc_pct < SOC_WARN_PCT) alarm = true;
    digitalWrite(BUZZ_PIN, alarm ? HIGH : LOW);

    // Persist SoC every 10 s (100 polls)
    static uint8_t persist_ctr = 0;
    if (++persist_ctr >= 100) {
      persist_ctr = 0;
      EEPROM.put(EE_SOC_ADDR, q_remain);
    }

    // Serial log
    Serial.printf("SoC=%.1f%% C1=%.3fV C2=%.3fV C3=%.3fV I=%.1fmA%s\n",
                  soc_pct, cell_v[0], cell_v[1], cell_v[2],
                  current_ma, alarm ? " ALARM" : "");
  }

  // --- 2. OLED refresh ---
  if (now - last_display >= DISPLAY_MS) {
    last_display = now;
    draw_oled();
  }
}
